    '    },',
    '    body: JSON.stringify({',
    '        question: question,',
    '        top_k: 5',
    '    })',
    '})',
    '.then(response => response.json())',
    '.then(data => {',
    '',
    '    if (data.success) {',
    '',
    '        document.getElementById("chat-window").innerHTML += `',
    '            <div style="margin:10px 0">',
    '                <b>You:</b> ${question}',
    '            </div>',
    '',
    '            <div style="margin:10px 0;background:#eef;padding:10px;border-radius:6px;">',
    '                <b>Assistant:</b><br>',
    '                ${data.answer}',
    '            </div>',
    '        `;',
    '',
    '        document.getElementById("chat-window").scrollTop =',
    '            document.getElementById("chat-window").scrollHeight;',
    '',
    '        $s("P1_QUESTION", "");',
    '',
    '    } else {',
    '        alert(data.error);',
    '    }',
    '',
    '})',
    '.catch(err => {',
    '    console.error(err);',
    '    alert("Cannot connect to Flask API.");',
    '});')))).to_clob
